template<typename T>
class array {
protected:
    std::vector<T> a;

public:
    array(std::vector<T> &a0) : a(a0) {}

    inline T operator[](size_t i) const {
        assert(i >= 0 && i < a.size());
        return a[i];
    }

    inline T select(size_t i) const {
        assert(i > 0 && i <= a.size());
        return a[i - 1];
    }

    inline size_t rank(T x) const {
        const T *base = a.data();
        size_t n = a.size();
        while (n > 1) {
            size_t half = n / 2;
            base = (base[half] < x) ? base + half : base;
            n -= half;
        }
        return (*base < x) + base - a.data();
    }

};

