unsigned int ZRandom::getValue(const uint32_t MaxValue) {
    unsigned int used = MaxValue;
    used |= used >> 1;
    used |= used >> 2;
    used |= used >> 4;
    used |= used >> 8;
    used |= used >> 16;

    // Draw numbers until one is found in [0,n]
    unsigned int i;
    do
        i = getValue() & used; // toss unused bits to shorten search
    while (i > MaxValue);
    return i;
}

